(function(){
  'use strict';
  var root=document.getElementById('mcc-coursemaker');
  if(!root||root.dataset.ready==='true')return;
  root.dataset.ready='true';
  var main=document.getElementById('cm-main');
  var palette=['#003366','#001B3B','#008DA7','#33A1FD','#FF6600','#EE7B30','#F7B32B','#D6E8EE','#000000','#FFFFFF'];
  var state={view:'builder',selected:null,page:null,widget:null};

  var templates={
    blank:{name:'Blank page',eyebrow:'Course content',description:'A clean starting point for any Brightspace page.',blocks:[]},
    content:{name:'Course content',eyebrow:'Learn',description:'A versatile instructional page with room for explanation and emphasis.',blocks:['lead','h2','text','callout','h2','text']},
    instructor:{name:'Meet your instructor',eyebrow:'Your course team',description:'Build presence by sharing your background, approach, and contact details.',blocks:['image','lead','h2','text','instructor']},
    module:{name:'Module overview page',eyebrow:'This week',description:'Set expectations and organize a week or module at a glance.',blocks:['lead','h2','list','callout','timeline']},
    'ai-red':{name:'Course AI policy: Red',eyebrow:'AI use is not permitted',description:'A red stoplight template for work students must complete without generative AI.',blocks:['lead','callout','h2','text','accordion'],tone:'red'},
    'ai-yellow':{name:'Course AI policy: Yellow',eyebrow:'Limited AI use',description:'A yellow stoplight template for assignments with defined, limited AI use.',blocks:['lead','callout','h2','text','accordion'],tone:'yellow'},
    'ai-green':{name:'Course AI policy: Green',eyebrow:'AI use is encouraged',description:'A green stoplight template for assignments where thoughtful AI use is permitted.',blocks:['lead','callout','h2','text','accordion'],tone:'green'}
  };
  var blockInfo={
    lead:['Intro text','Text'],h2:['Section heading','Text'],text:['Paragraph','Text'],list:['Checklist','Text'],callout:['Callout box','Featured'],quote:['Blockquote','Featured'],button:['Button link','Featured'],colored:['Colored block','Featured'],instructor:['Instructor insight','Featured'],accordion:['Accordion (1–6)','Interactive'],tabs:['Tabbed sections','Interactive'],flip:['Flip card','Interactive'],timeline:['Timeline','Interactive'],image:['Image','Media'],video:['Video','Media'],table:['Table','Data'],divider:['Divider','Layout']
  };
  var widgetInfo={
    instructor:['Instructor information','Photo, contact details, office information, and a Teams message button.'],
    links:['Important links','A compact set of buttons for the course syllabus and MCC student services.'],
    weekly:['This week','A concise weekly focus with tasks, dates, and an optional course link.'],
    announcement:['Course announcement','A dated announcement, reminder, or welcome message with an optional action.'],
    blank:['Blank widget','A simple title, text area, and optional button for a custom widget.']
  };

  function uid(prefix){return prefix+'-'+Date.now()+'-'+Math.random().toString(16).slice(2)}
  function esc(value){return String(value==null?'':value).replace(/[&<>"']/g,function(c){return {'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[c]})}
  function lines(value){return String(value||'').split(/\r?\n/).map(function(x){return x.trim()}).filter(Boolean)}
  function nl(value){return esc(value).replace(/\r?\n/g,'<br>')}
  function textColor(hex){var h=String(hex||'#003366').replace('#','');if(h.length===3)h=h.split('').map(function(c){return c+c}).join('');var r=parseInt(h.slice(0,2),16)||0,g=parseInt(h.slice(2,4),16)||0,b=parseInt(h.slice(4,6),16)||0;return ((r*299+g*587+b*114)/1000)>160?'#001B3B':'#FFFFFF'}
  function safeUrl(value){var v=String(value||'').trim();if(!v)return '';if(/^(https?:|mailto:|tel:|\/|#)/i.test(v))return esc(v);return esc(v)}
  function newBlock(type){
    var base={id:uid(type),type:type,title:'',content:'',url:'',color:''};
    var defs={
      lead:{content:'Use this short introduction to orient students to the page.'},
      h2:{title:'Section heading'},
      text:{content:'Add your course content here. Keep paragraphs focused and use headings to organize longer pages.'},
      list:{title:'In this section, you will:',content:'Review the materials\nComplete the activity\nCheck your understanding',listStyle:'bullets'},
      callout:{title:'Good to know',content:'Highlight a deadline, key idea, or helpful reminder.'},
      quote:{content:'Add a short quotation or a memorable idea here.'},
      button:{title:'Open course resource',url:'https://www.mclennan.edu/'},
      colored:{title:'Featured information',content:'Use this colored block to emphasize a key idea, direction, or reminder.',color:'#003366'},
      instructor:{title:'Instructor Insight',content:'Share a concise teaching insight, practical example, or recommendation for students.',url:'',color:'#FF6600'},
      accordion:{title:'Accordion group',count:3,items:[{title:'Select to learn more',content:'Place optional details or guidance here.'},{title:'Explore an example',content:'Add a relevant example or supporting information.'},{title:'Check your understanding',content:'Add a brief reflection prompt or reminder.'}]},
      tabs:{title:'Tabbed content',layout:'horizontal',count:3,items:[{title:'Overview',content:'Introduce the topic or activity.'},{title:'Example',content:'Provide an example or model.'},{title:'Next steps',content:'Explain what students should do next.'}]},
      flip:{title:'Key concept',content:'Select the card to reveal more.',url:'',backTitle:'What it means',backContent:'Add the explanation, answer, or additional detail here.',backUrl:''},
      timeline:{title:'Course timeline',layout:'vertical',count:3,color:'#008DA7',items:[{title:'Step 1',content:'Add the first milestone or event.'},{title:'Step 2',content:'Add the next milestone or event.'},{title:'Step 3',content:'Add the final milestone or event.'}]},
      image:{title:'Descriptive image alt text',content:'Optional image caption',url:''},
      video:{title:'Course video',content:'A short description of the video.',url:'https://www.youtube.com/embed/ZZ5LpwO-An4'},
      table:{title:'Course schedule',content:'Week|Topic|Due\n1|Getting started|Sunday\n2|Core concepts|Sunday'},
      divider:{}
    };
    return Object.assign(base,defs[type]||{});
  }
  function makePage(templateKey){
    var t=templates[templateKey]||templates.blank;
    var blocks=t.blocks.map(newBlock);
    if(t.tone){
      var call=blocks.find(function(b){return b.type==='callout'}),lead=blocks.find(function(b){return b.type==='lead'});
      var data={red:['RED: Generative AI is not permitted','Complete this work using your own knowledge, course resources, and approved support.','#B42318'],yellow:['YELLOW: Generative AI use is limited','Use generative AI only for the specific purposes identified by your instructor.','#9A6700'],green:['GREEN: Generative AI use is permitted','You may use generative AI as directed, but you remain responsible for accuracy, attribution, and the final work.','#18794E']}[t.tone];
      if(call){call.title=data[0];call.content=data[1];call.color=data[2]}
      if(lead)lead.content='This policy explains how generative AI may be used in this course or assignment.';
    }
    return {template:templateKey,eyebrow:t.eyebrow,title:t.name,titleStyle:'banner',bannerUrl:'',accent:'#003366',blocks:blocks};
  }
  function makeWidget(type){
    var common={template:type,title:'Widget Title',subtitle:'',accent:'#003366',name:'',role:'',imageUrl:'',email:'',office:'',officeHours:'',showImage:false,showEmail:false,showOffice:false,showOfficeHours:false,showTeams:false,syllabusUrl:'',content:'',items:'',date:'',buttonLabel:'',buttonUrl:''};
    var defs={
      instructor:{title:'Your Instructor',subtitle:'Welcome to the course',name:'Instructor Name',role:'Course Instructor',email:'instructor@mclennan.edu',office:'Office location',officeHours:'Office hours by appointment',showImage:true,showEmail:true,showOffice:true,showOfficeHours:true,showTeams:true},
      links:{title:'Important Links',subtitle:'Quick access'},
      weekly:{title:'This Week',subtitle:'Module focus',accent:'#008DA7',content:'Use this space to summarize the week and help students focus on what matters most.',items:'Review the module materials\nComplete the learning activity\nSubmit work by Sunday',date:'This week',buttonLabel:'Open this module'},
      announcement:{title:'Course Announcement',subtitle:'Important update',accent:'#FF6600',content:'Share a welcome message, deadline reminder, or important course update.',date:'Posted today',buttonLabel:'View course details'},
      blank:{title:'Widget Title',content:'Add your widget content here.'}
    };
    return Object.assign(common,defs[type]||{});
  }
  state.page=makePage('blank');state.widget=makeWidget('instructor');

  function swatches(value,attr){return '<div class="cm-swatches">'+palette.map(function(c){return '<button type="button" class="cm-swatch" data-'+attr+'="'+c+'" aria-label="Use color '+c+'" aria-pressed="'+(String(value).toUpperCase()===c?'true':'false')+'" style="background:'+c+'"></button>'}).join('')+'</div>'}
  function breadcrumbs(items){return '<nav class="cm-breadcrumbs cm-shell" aria-label="Breadcrumb"><button type="button" data-view="home">CourseMaker</button>'+items.map(function(x){return '<span><span aria-hidden="true">/</span> '+esc(x)+'</span>'}).join('')+'</nav>'}
  function toast(message){var el=document.getElementById('cm-toast');el.textContent=message;el.classList.add('cm-show');clearTimeout(toast.timer);toast.timer=setTimeout(function(){el.classList.remove('cm-show')},2600)}
  function copyText(value,message){
    function fallback(){var ta=document.createElement('textarea');ta.value=value;ta.style.position='fixed';ta.style.opacity='0';document.body.appendChild(ta);ta.select();try{document.execCommand('copy');toast(message||'Copied to clipboard.')}catch(e){toast('Select the code and copy it manually.')}document.body.removeChild(ta)}
    if(navigator.clipboard&&window.isSecureContext)navigator.clipboard.writeText(value).then(function(){toast(message||'Copied to clipboard.')},fallback);else fallback();
  }
  function downloadText(value,name){var blob=new Blob([value],{type:'text/html;charset=utf-8'}),url=URL.createObjectURL(blob),a=document.createElement('a');a.href=url;a.download=name;document.body.appendChild(a);a.click();a.remove();setTimeout(function(){URL.revokeObjectURL(url)},1000);toast(name+' downloaded.')}
  function contrastNote(color){return textColor(color)==='#FFFFFF'?'White text will be used for contrast.':'Dark navy text will be used for contrast.'}

  function renderBlock(b,accent,preview){
    var color=b.color||accent||'#003366',on=textColor(color),title=esc(b.title),content=nl(b.content),wrapStart=preview?'<div data-cm-block-id="'+esc(b.id)+'">':'',wrapEnd=preview?'</div>':'';
    var html='';
    if(b.type==='lead')html='<p style="font-family:Lato,Arial,sans-serif;font-size:23px;line-height:1.55;color:#334E5C;margin:0 0 26px">'+content+'</p>';
    if(b.type==='h2')html='<h2 style="font-family:Lato,Arial,sans-serif;color:'+color+';font-size:30px;line-height:1.25;margin:32px 0 12px">'+title+'</h2>';
    if(b.type==='text')html='<p style="font-family:Lato,Arial,sans-serif;font-size:19px;color:#1F2933;line-height:1.65;margin:0 0 20px">'+content+'</p>';
    if(b.type==='callout')html='<div style="font-family:Lato,Arial,sans-serif;font-size:19px;line-height:1.65;border-left:6px solid '+color+';background:#F3F7F8;padding:18px 20px;margin:24px 0"><h2 style="font-family:Lato,Arial,sans-serif;color:'+color+';font-size:25px;line-height:1.3;margin:0 0 8px">'+title+'</h2><p style="margin:0">'+content+'</p></div>';
    if(b.type==='list'){
      var its=lines(b.content);
      if(b.listStyle==='interactive')html='<div style="font-family:Lato,Arial,sans-serif;font-size:19px;margin:24px 0"><h2 style="color:'+color+';font-size:25px;margin:0 0 10px">'+title+'</h2><div>'+its.map(function(x,i){return '<label style="display:flex;align-items:flex-start;gap:10px;margin:9px 0"><input type="checkbox" style="width:20px;height:20px;margin-top:5px;accent-color:'+color+'"><span>'+esc(x)+'</span></label>'}).join('')+'</div></div>';
      else html='<div style="font-family:Lato,Arial,sans-serif;font-size:19px;margin:24px 0"><h2 style="color:'+color+';font-size:25px;margin:0 0 10px">'+title+'</h2><ul style="padding-left:27px;margin:0">'+its.map(function(x){return '<li style="margin:7px 0">'+esc(x)+'</li>'}).join('')+'</ul></div>';
    }
    if(b.type==='quote')html='<blockquote style="font-family:Lato,Arial,sans-serif;font-size:23px;line-height:1.55;color:#334E5C;border-left:6px solid '+color+';margin:28px 0;padding:8px 0 8px 22px"><p style="margin:0">“'+content+'”</p></blockquote>';
    if(b.type==='divider')html='<hr style="border:0;border-top:2px solid #C9D7DE;margin:34px 0">';
    if(b.type==='button')html='<p style="font-family:Lato,Arial,sans-serif;font-size:19px;margin:24px 0"><a href="'+safeUrl(b.url)+'" style="display:inline-block;background:'+color+';color:'+textColor(color)+';text-decoration:none;border-radius:6px;padding:12px 18px;font-weight:700">'+title+'</a></p>';
    if(b.type==='image')html=b.url?'<figure style="font-family:Lato,Arial,sans-serif;font-size:19px;margin:24px 0"><img src="'+safeUrl(b.url)+'" alt="'+title+'" style="display:block;width:100%;height:auto;border-radius:10px"><figcaption style="color:#4B5563;font-size:17px;margin-top:8px">'+content+'</figcaption></figure>':'<div style="font-family:Lato,Arial,sans-serif;font-size:19px;margin:24px 0;background:#EEF3F5;border:2px dashed #9FB6C1;padding:40px;text-align:center;color:#566772">Add an image URL<br><strong>'+title+'</strong></div>';
    if(b.type==='video')html='<div style="font-family:Lato,Arial,sans-serif;font-size:19px;margin:24px 0"><div style="position:relative;padding-top:56.25%;overflow:hidden;border-radius:10px;background:#001B3B"><iframe src="'+safeUrl(b.url)+'" title="'+title+'" allowfullscreen style="position:absolute;inset:0;width:100%;height:100%;border:0"></iframe></div><p style="color:#4B5563;font-size:17px;margin:8px 0 0">'+content+'</p></div>';
    if(b.type==='table'){
      var rows=lines(b.content).map(function(r){return r.split('|')});var head=rows.shift()||[];
      html='<div style="overflow-x:auto;margin:24px 0"><table style="width:100%;border-collapse:collapse;font-family:Lato,Arial,sans-serif;font-size:19px"><caption style="font-weight:700;text-align:left;color:'+color+';font-size:23px;margin-bottom:10px">'+title+'</caption><thead><tr>'+head.map(function(c){return '<th scope="col" style="background:'+color+';color:'+textColor(color)+';text-align:left;border:1px solid #9FB6C1;padding:10px">'+esc(c)+'</th>'}).join('')+'</tr></thead><tbody>'+rows.map(function(r){return '<tr>'+r.map(function(c){return '<td style="border:1px solid #9FB6C1;padding:10px">'+esc(c)+'</td>'}).join('')+'</tr>'}).join('')+'</tbody></table></div>';
    }
    if(b.type==='accordion')html='<div style="font-family:Lato,Arial,sans-serif;font-size:19px;margin:24px 0"><h2 style="color:'+color+';font-size:25px;margin:0 0 12px">'+title+'</h2>'+b.items.slice(0,b.count||1).map(function(item){return '<details style="border:1px solid '+color+';border-radius:8px;margin:0 0 10px;overflow:hidden"><summary style="cursor:pointer;background:'+color+';color:'+textColor(color)+';font-weight:700;padding:16px 18px">'+esc(item.title)+'</summary><div style="font-family:Lato,Arial,sans-serif;font-size:19px;color:#1F2933;line-height:1.65;padding:16px 18px">'+nl(item.content)+'</div></details>'}).join('')+'</div>';
    if(b.type==='tabs'){
      var items=b.items.slice(0,Math.min(3,b.count||3)),vertical=b.layout==='vertical',tabId='tabs-'+b.id.replace(/[^a-z0-9_-]/gi,'');
      html='<div data-cm-tabs="'+tabId+'" data-cm-accent="'+color+'" style="font-family:Lato,Arial,sans-serif;font-size:19px;margin:24px 0"><h2 style="color:'+color+';font-size:25px;margin:0 0 12px">'+title+'</h2><div style="display:'+ (vertical?'grid':'block') +';grid-template-columns:'+ (vertical?'minmax(150px,30%) 1fr':'none') +';gap:'+ (vertical?'12px':'0') +'">'+
        '<div role="tablist" aria-label="'+title+'" style="display:flex;flex-direction:'+(vertical?'column':'row')+';gap:4px;flex-wrap:wrap">'+items.map(function(item,i){return '<button type="button" role="tab" aria-selected="'+(i===0)+'" data-cm-tab="'+i+'" style="font-family:Lato,Arial,sans-serif;font-size:19px;font-weight:700;text-align:left;border:1px solid #9FB6C1;background:'+(i===0?color:'#F3F7F8')+';color:'+(i===0?textColor(color):'#001B3B')+';padding:12px 15px;flex:'+(vertical?'none':'1')+'">'+esc(item.title)+'</button>'}).join('')+'</div>'+
        '<div>'+items.map(function(item,i){return '<div role="tabpanel" data-cm-panel="'+i+'" '+(i?'hidden':'')+' style="font-family:Lato,Arial,sans-serif;font-size:19px;color:#1F2933;line-height:1.65;padding:20px;border:1px solid #9FB6C1">'+nl(item.content)+'</div>'}).join('')+'</div></div></div>';
    }
    if(b.type==='flip')html='<div style="font-family:Lato,Arial,sans-serif;font-size:19px;margin:24px 0;text-align:center"><button type="button" data-cm-flip aria-pressed="false" style="width:100%;min-height:330px;border:0;background:transparent;perspective:1000px;padding:0"><span data-cm-flip-inner style="position:relative;display:block;width:100%;min-height:330px;transition:transform .6s;transform-style:preserve-3d"><span style="position:absolute;inset:0;display:flex;align-items:center;justify-content:center;background:#F3F7F8;border:3px solid '+color+';border-radius:12px;overflow:hidden;backface-visibility:hidden">'+(b.url?'<img src="'+safeUrl(b.url)+'" alt="" style="position:absolute;inset:0;width:100%;height:100%;object-fit:cover;opacity:.22">':'')+'<span style="position:relative;padding:28px"><strong style="display:block;font-size:26px;color:#001B3B;margin-bottom:8px">'+title+'</strong><span style="display:block;font-size:19px;color:#1F2933;line-height:1.6">'+content+'</span><span style="display:block;font-size:16px;color:'+color+';font-weight:700;margin-top:16px">Select to flip</span></span></span><span style="position:absolute;inset:0;display:flex;align-items:center;justify-content:center;background:'+color+';color:'+textColor(color)+';border-radius:12px;overflow:hidden;transform:rotateY(180deg);backface-visibility:hidden">'+(b.backUrl?'<img src="'+safeUrl(b.backUrl)+'" alt="" style="position:absolute;inset:0;width:100%;height:100%;object-fit:cover;opacity:.2">':'')+'<span style="position:relative;padding:28px"><strong style="display:block;font-size:26px;margin-bottom:8px">'+esc(b.backTitle)+'</strong><span style="display:block;font-size:19px;line-height:1.6">'+nl(b.backContent)+'</span><span style="display:block;font-size:16px;font-weight:700;margin-top:16px">Select to return</span></span></span></span></button></div>';
    if(b.type==='colored')html='<div style="font-family:Lato,Arial,sans-serif;font-size:19px;line-height:1.65;background:'+color+';color:'+on+';border:1px solid '+(color==='#FFFFFF'?'#9FB6C1':color)+';border-radius:10px;padding:22px;margin:24px 0"><h2 style="font-size:25px;line-height:1.3;margin:0 0 8px;color:'+on+'">'+title+'</h2><p style="margin:0;color:'+on+'">'+content+'</p></div>';
    if(b.type==='timeline'){
      var titems=b.items.slice(0,b.count||1),horizontal=b.layout==='horizontal';
      html='<div style="font-family:Lato,Arial,sans-serif;font-size:19px;margin:24px 0"><h2 style="color:'+color+';font-size:25px;margin:0 0 18px">'+title+'</h2><div style="'+(horizontal?'display:flex;flex-wrap:wrap;gap:14px':'border-left:5px solid '+color+';margin-left:16px;padding-left:24px')+'">'+titems.map(function(item,i){return '<div style="position:relative;'+(horizontal?'flex:1 1 180px;border-top:5px solid '+color+';padding:16px;background:#F3F7F8':'margin:0 0 24px')+'"><span style="display:inline-grid;place-items:center;width:34px;height:34px;border-radius:50%;background:'+color+';color:'+textColor(color)+';font-weight:700;'+(!horizontal?'position:absolute;left:-44px;top:0':'margin-bottom:10px')+'">'+(i+1)+'</span><h3 style="color:#001B3B;font-size:21px;margin:0 0 6px">'+esc(item.title)+'</h3><p style="font-size:19px;color:#1F2933;line-height:1.55;margin:0">'+nl(item.content)+'</p></div>'}).join('')+'</div></div>';
    }
    if(b.type==='instructor')html='<div style="background-color:#FFF4EF;border-left:4px solid '+color+';padding:10px 15px;margin:24px 0;font-family:Lato,Arial,sans-serif;font-size:19px;line-height:1.65"><table role="presentation" style="border:0;border-collapse:collapse;width:100%;vertical-align:top"><tbody><tr>'+(b.url?'<td style="width:18%;padding-right:15px"><img src="'+safeUrl(b.url)+'" alt="" style="max-width:100%;height:auto;border-radius:8px"></td>':'')+'<td style="vertical-align:top"><p style="margin:0"><strong>'+title+' — </strong>'+content+'</p></td></tr></tbody></table></div>';
    return wrapStart+html+wrapEnd;
  }
  function interactionScript(){return '<script>(function(){document.querySelectorAll("[data-cm-tabs]").forEach(function(g){g.querySelectorAll("[data-cm-tab]").forEach(function(b){b.addEventListener("click",function(){var n=b.getAttribute("data-cm-tab"),c=(g.getAttribute("data-cm-accent")||"#003366").toUpperCase(),dark=["#33A1FD","#F7B32B","#D6E8EE","#FFFFFF"].indexOf(c)>-1;g.querySelectorAll("[data-cm-tab]").forEach(function(x){var on=x===b;x.setAttribute("aria-selected",on);x.style.background=on?c:"#F3F7F8";x.style.color=on?(dark?"#001B3B":"#FFFFFF"):"#001B3B"});g.querySelectorAll("[data-cm-panel]").forEach(function(p){p.hidden=p.getAttribute("data-cm-panel")!==n})})})});document.querySelectorAll("[data-cm-flip]").forEach(function(b){b.addEventListener("click",function(){var on=b.getAttribute("aria-pressed")==="true";b.setAttribute("aria-pressed",String(!on));b.querySelector("[data-cm-flip-inner]").style.transform=on?"rotateY(0deg)":"rotateY(180deg)"})})})();<\/script>'}
  function pageHTML(preview){
    var p=state.page,accent=p.accent||'#003366',on=textColor(accent),banner='';
    if(p.titleStyle==='text')banner='<div style="font-family:Lato,Arial,sans-serif;padding:36px clamp(20px,4vw,48px);border-bottom:5px solid '+accent+'"><p style="color:'+accent+';font-size:16px;font-weight:700;letter-spacing:.12em;text-transform:uppercase;margin:0 0 7px">'+esc(p.eyebrow)+'</p><h1 style="color:#001B3B;font-size:48px;line-height:1.15;margin:0">'+esc(p.title)+'</h1></div>';
    else banner='<div style="font-family:Lato,Arial,sans-serif;padding:44px clamp(20px,4vw,48px);background:'+(p.bannerUrl?'linear-gradient(rgba(0,27,59,.72),rgba(0,27,59,.72)),url(\''+safeUrl(p.bannerUrl)+'\') center/cover no-repeat':accent)+'"><p style="color:'+on+';font-size:16px;font-weight:700;letter-spacing:.12em;text-transform:uppercase;margin:0 0 7px">'+esc(p.eyebrow)+'</p><h1 style="color:'+on+';font-size:48px;line-height:1.15;margin:0">'+esc(p.title)+'</h1></div>';
    var body=p.blocks.length?p.blocks.map(function(b){return renderBlock(b,accent,preview)}).join(''):'<div class="cm-empty-preview" style="font-family:Lato,Arial,sans-serif;font-size:19px;color:#566772"><div><strong style="display:block;color:#001B3B">Your page is ready for content.</strong>Add a building block from the left panel.</div></div>';
    var hasInteractive=p.blocks.some(function(b){return b.type==='tabs'||b.type==='flip'});
    return '<div style="max-width:1100px;margin:0 auto;background:#FFFFFF;font-family:Lato,Arial,sans-serif;font-size:19px;color:#1F2933;line-height:1.65">'+banner+'<div style="padding:36px clamp(20px,4vw,48px)">'+body+'</div><div style="font-family:Lato,Arial,sans-serif;background:#001B3B;color:#FFFFFF;font-size:16px;padding:16px clamp(20px,4vw,48px)">McLennan Community College</div></div>'+(!preview&&hasInteractive?interactionScript():'');
  }
  function bindPreviewInteractions(){
    var stage=document.getElementById('cm-page-render');if(!stage)return;
    stage.querySelectorAll('[data-cm-block-id]').forEach(function(el){el.addEventListener('click',function(e){if(e.target.closest('button,a,input,summary'))return;state.selected=el.getAttribute('data-cm-block-id');renderPageBuilder()})});
    stage.querySelectorAll('[data-cm-tab]').forEach(function(btn){btn.addEventListener('click',function(){var g=btn.closest('[data-cm-tabs]'),n=btn.getAttribute('data-cm-tab'),color=g.getAttribute('data-cm-accent')||state.page.accent;g.querySelectorAll('[data-cm-tab]').forEach(function(x){var on=x===btn;x.setAttribute('aria-selected',on);x.style.background=on?color:'#F3F7F8';x.style.color=on?textColor(color):'#001B3B'});g.querySelectorAll('[data-cm-panel]').forEach(function(p){p.hidden=p.getAttribute('data-cm-panel')!==n})})});
    stage.querySelectorAll('[data-cm-flip]').forEach(function(btn){btn.addEventListener('click',function(){var on=btn.getAttribute('aria-pressed')==='true';btn.setAttribute('aria-pressed',String(!on));btn.querySelector('[data-cm-flip-inner]').style.transform=on?'rotateY(0deg)':'rotateY(180deg)'})});
  }
  function selectedBlock(){return state.page.blocks.find(function(b){return b.id===state.selected})||null}
  function field(label,key,value,type,extra){type=type||'text';return '<label>'+esc(label)+(type==='textarea'?'<textarea data-block-key="'+key+'" '+(extra||'')+'>'+esc(value)+'</textarea>':'<input type="'+type+'" data-block-key="'+key+'" value="'+esc(value)+'" '+(extra||'')+'>')+'</label>'}
  function itemFields(b){
    if(!b.items)return '';
    return b.items.slice(0,b.count||b.items.length).map(function(item,i){return '<div class="cm-multi-item"><strong>Item '+(i+1)+'</strong>'+field('Title','item-title-'+i,item.title)+field('Content','item-content-'+i,item.content,'textarea','rows="3"')+'</div>'}).join('');
  }
  function inspectorHTML(){
    var b=selectedBlock();if(!b)return '<div class="cm-panel-inner"><h2>Block editor</h2><div class="cm-inspector-empty"><span aria-hidden="true">↖</span><p>Select a block in the preview to edit it. Its customized HTML snippet will appear here.</p></div></div>';
    var out='<div class="cm-panel-inner"><div class="cm-inspector-head"><h2>'+esc(blockInfo[b.type][0])+'</h2><button type="button" class="cm-small-button" data-action="delete">Delete</button></div><div class="cm-editor-actions"><button type="button" data-action="up">Move up</button><button type="button" data-action="down">Move down</button></div>';
    if(['h2','callout','list','button','colored','instructor','accordion','tabs','flip','timeline','image','video','table'].indexOf(b.type)>-1)out+=field(b.type==='image'?'Alt text':b.type==='video'?'Video title':'Title','title',b.title);
    if(['lead','text','callout','list','quote','colored','instructor','flip','image','video','table'].indexOf(b.type)>-1)out+=field(b.type==='list'?'Items (one per line)':b.type==='table'?'Rows (use | between columns)':'Content','content',b.content,'textarea','rows="5"');
    if(b.type==='list')out+='<label>Checklist style<select data-block-key="listStyle"><option value="bullets" '+(b.listStyle==='bullets'?'selected':'')+'>Simple bullet points</option><option value="interactive" '+(b.listStyle==='interactive'?'selected':'')+'>Interactive checkboxes</option></select></label>';
    if(['button','image','video','instructor'].indexOf(b.type)>-1)out+=field(b.type==='instructor'?'Optional instructor image URL':b.type==='image'?'Image URL':b.type==='video'?'Embed URL':'Link URL','url',b.url,'text','placeholder="https://... or /content/..."');
    if(['h2','list','callout','quote','button','colored','instructor','accordion','tabs','flip','timeline','table'].indexOf(b.type)>-1)out+='<fieldset><legend>Block color</legend><button type="button" class="cm-small-button" data-block-color="" style="margin-bottom:.6rem">Use page color</button>'+swatches(b.color||state.page.accent,'block-color')+'<p class="cm-field-note">'+contrastNote(b.color||state.page.accent)+'</p></fieldset>';
    if(b.type==='accordion')out+='<label>Number of sections<select data-count>'+[1,2,3,4,5,6].map(function(n){return '<option '+(b.count===n?'selected':'')+'>'+n+'</option>'}).join('')+'</select></label>'+itemFields(b);
    if(b.type==='tabs')out+='<label>Tab orientation<select data-block-key="layout"><option value="horizontal" '+(b.layout==='horizontal'?'selected':'')+'>Horizontal</option><option value="vertical" '+(b.layout==='vertical'?'selected':'')+'>Vertical</option></select></label><label>Number of tabs<select data-count>'+[1,2,3].map(function(n){return '<option '+(b.count===n?'selected':'')+'>'+n+'</option>'}).join('')+'</select></label>'+itemFields(b);
    if(b.type==='timeline')out+='<label>Orientation<select data-block-key="layout"><option value="vertical" '+(b.layout==='vertical'?'selected':'')+'>Vertical</option><option value="horizontal" '+(b.layout==='horizontal'?'selected':'')+'>Horizontal</option></select></label><label>Number of selections<select data-count>'+[1,2,3,4,5,6].map(function(n){return '<option '+(b.count===n?'selected':'')+'>'+n+'</option>'}).join('')+'</select></label>'+itemFields(b);
    if(b.type==='flip')out+=field('Front image URL','url',b.url)+field('Back title','backTitle',b.backTitle)+field('Back text','backContent',b.backContent,'textarea','rows="4"')+field('Back image URL','backUrl',b.backUrl);
    var snippet=renderBlock(b,state.page.accent,false);
    out+='<h3>Customized code snippet</h3><p class="cm-field-note">This is only the selected block, updated as you edit.</p><code class="cm-code" id="cm-block-code">'+esc(snippet)+'</code><div class="cm-code-actions"><button type="button" data-action="copy-block">Copy snippet</button></div></div>';
    return out;
  }
  function setupHTML(){
    var p=state.page;
    return '<section><h2>Page setup</h2><label>Starter template<select id="cm-template-select">'+Object.keys(templates).map(function(k){return '<option value="'+k+'" '+(p.template===k?'selected':'')+'>'+esc(templates[k].name)+'</option>'}).join('')+'</select></label><label>Page label<input id="cm-page-eyebrow" value="'+esc(p.eyebrow)+'"></label><label>Page title<input id="cm-page-title" value="'+esc(p.title)+'"></label><label>Title style<select id="cm-title-style"><option value="banner" '+(p.titleStyle==='banner'?'selected':'')+'>MCC color banner</option><option value="text" '+(p.titleStyle==='text'?'selected':'')+'>Text only — no banner</option></select></label><label>Optional banner image URL<input id="cm-banner-url" value="'+esc(p.bannerUrl)+'" placeholder="https://..."></label><fieldset><legend>Accent color</legend>'+swatches(p.accent,'page-color')+'<p class="cm-field-note">'+contrastNote(p.accent)+'</p></fieldset></section>';
  }
  function libraryHTML(){
    var cats=['Text','Featured','Interactive','Media','Data','Layout'];
    return '<section><h2>Building blocks</h2><p class="cm-field-note">Select a block to add it to the bottom of the page.</p>'+cats.map(function(cat){var items=Object.keys(blockInfo).filter(function(k){return blockInfo[k][1]===cat});return '<h3>'+cat+'</h3><div class="cm-tool-grid">'+items.map(function(k){return '<button type="button" data-add-block="'+k+'"><span aria-hidden="true">＋</span> '+esc(blockInfo[k][0])+'</button>'}).join('')+'</div>'}).join('')+'</section>';
  }
  function renderPageBuilder(){
    state.view='builder';updateNav();
    main.innerHTML='<div class="cm-builder-page">'+breadcrumbs(['Build','Page Builder'])+'<div class="cm-shell cm-builder-heading"><div><p class="cm-eyebrow cm-eyebrow-dark">Visual Brightspace page builder</p><h1>Build your page</h1><p>Add blocks, edit the details, and copy the finished HTML into Brightspace.</p></div><div class="cm-top-actions"><button class="cm-button cm-secondary" type="button" id="cm-reset-page">Reset page</button><button class="cm-button cm-secondary" type="button" id="cm-download-page">Download HTML</button><button class="cm-button cm-primary" type="button" id="cm-copy-page">Copy page HTML</button></div></div><div class="cm-builder-shell cm-shell"><aside class="cm-panel" aria-label="Page controls and building blocks">'+setupHTML()+libraryHTML()+'</aside><section class="cm-workspace" aria-label="Page preview"><div class="cm-workspace-label"><h2>Page preview</h2><span>'+state.page.blocks.length+' blocks</span></div><div class="cm-preview-stage"><div class="cm-preview-page" id="cm-page-render">'+pageHTML(true)+'</div></div></section><aside class="cm-panel cm-inspector" id="cm-inspector" aria-label="Block editor">'+inspectorHTML()+'</aside></div><div class="cm-shell cm-builder-note" role="note"><strong>Brightspace tip:</strong> Copy the finished HTML into the Brightspace HTML source editor, or download the page and upload it to Manage Files. Preview the page as a learner before publishing.</div></div>';
    bindPageBuilder();bindPreviewInteractions();
  }
  function refreshBuilder(preserveInspector){
    var render=document.getElementById('cm-page-render');if(render)render.innerHTML=pageHTML(true);
    var ins=document.getElementById('cm-inspector');
    if(ins&&!preserveInspector){ins.innerHTML=inspectorHTML();bindInspector()}
    if(preserveInspector){var b=selectedBlock(),code=document.getElementById('cm-block-code');if(b&&code)code.textContent=renderBlock(b,state.page.accent,false)}
    bindPreviewInteractions();
  }
  function bindPageBuilder(){
    document.getElementById('cm-template-select').addEventListener('change',function(){state.page=makePage(this.value);state.selected=null;renderPageBuilder()});
    [['cm-page-eyebrow','eyebrow'],['cm-page-title','title'],['cm-banner-url','bannerUrl']].forEach(function(pair){document.getElementById(pair[0]).addEventListener('input',function(){state.page[pair[1]]=this.value;refreshBuilder(true)})});
    document.getElementById('cm-title-style').addEventListener('change',function(){state.page.titleStyle=this.value;refreshBuilder(true)});
    document.querySelectorAll('[data-page-color]').forEach(function(btn){btn.addEventListener('click',function(){state.page.accent=btn.getAttribute('data-page-color');renderPageBuilder()})});
    document.querySelectorAll('[data-add-block]').forEach(function(btn){btn.addEventListener('click',function(){var b=newBlock(btn.getAttribute('data-add-block'));state.page.blocks.push(b);state.selected=b.id;renderPageBuilder()})});
    document.getElementById('cm-reset-page').addEventListener('click',function(){if(confirm('Reset this page and remove your current edits?')){state.page=makePage('blank');state.selected=null;renderPageBuilder()}});
    document.getElementById('cm-copy-page').addEventListener('click',function(){copyText(pageHTML(false),'Page HTML copied.')});
    document.getElementById('cm-download-page').addEventListener('click',function(){downloadText('<!DOCTYPE html><html lang="en"><body>'+pageHTML(false)+'</body></html>','MCC-Brightspace-Page.html')});
    bindInspector();
  }
  function ensureItems(b,count){while(b.items.length<count)b.items.push({title:(b.type==='timeline'?'Step ':'Section ')+(b.items.length+1),content:'Add the details here.'});b.count=count}
  function bindInspector(){
    var b=selectedBlock();if(!b)return;
    document.querySelectorAll('[data-block-key]').forEach(function(el){var key=el.getAttribute('data-block-key');if(key.indexOf('item-')===0)return;el.addEventListener(el.tagName==='SELECT'?'change':'input',function(){b[key]=el.value;refreshBuilder(true)})});
    document.querySelectorAll('[data-block-color]').forEach(function(btn){btn.addEventListener('click',function(){b.color=btn.getAttribute('data-block-color');refreshBuilder()})});
    var count=document.querySelector('[data-count]');if(count)count.addEventListener('change',function(){ensureItems(b,parseInt(count.value,10));renderPageBuilder()});
    document.querySelectorAll('[data-block-key^="item-"]').forEach(function(el){el.addEventListener('input',function(){var parts=el.getAttribute('data-block-key').split('-'),key=parts[1],idx=parseInt(parts[2],10);b.items[idx][key]=el.value;refreshBuilder(true)})});
    document.querySelectorAll('[data-action]').forEach(function(btn){btn.addEventListener('click',function(){var action=btn.getAttribute('data-action'),i=state.page.blocks.indexOf(b);if(action==='delete'){state.page.blocks.splice(i,1);state.selected=null;renderPageBuilder()}if(action==='up'&&i>0){state.page.blocks.splice(i,1);state.page.blocks.splice(i-1,0,b);renderPageBuilder()}if(action==='down'&&i<state.page.blocks.length-1){state.page.blocks.splice(i,1);state.page.blocks.splice(i+1,0,b);renderPageBuilder()}if(action==='copy-block')copyText(renderBlock(b,state.page.accent,false),'Block snippet copied.')})});
  }

  function widgetHeader(w){var on=textColor(w.accent);return '<div style="background:'+w.accent+';border-top:5px solid #FF6600;border-radius:8px 8px 0 0;padding:12px 18px;text-align:center"><h2 style="font-family:Lato,Arial,sans-serif;font-size:21px;line-height:1.2;color:'+on+';margin:0">'+esc(w.title)+'</h2>'+(w.subtitle?'<p style="font-family:Lato,Arial,sans-serif;font-size:13px;line-height:1.4;color:'+on+';margin:4px 0 0;opacity:.9">'+esc(w.subtitle)+'</p>':'')+'</div>'}
  function widgetHTML(){
    var w=state.widget,on=textColor(w.accent),body='';
    if(w.template==='instructor')body='<div style="background:#FFFFFF;border:1px solid #D5E0E5;border-top:0;border-radius:0 0 8px 8px;padding:18px;text-align:center">'+(w.showImage?(w.imageUrl?'<img src="'+safeUrl(w.imageUrl)+'" alt="Photo of '+esc(w.name)+'" style="width:110px;height:110px;border-radius:50%;object-fit:cover;border:4px solid '+w.accent+';display:block;margin:0 auto 12px">':'<div style="width:110px;height:110px;border-radius:50%;border:4px solid '+w.accent+';background:#EAF2F5;display:grid;place-items:center;font-family:Lato,Arial,sans-serif;font-size:13px;margin:0 auto 14px">Add photo URL</div>'):'')+'<h3 style="font-family:Lato,Arial,sans-serif;font-size:22px;line-height:1.2;color:#001B3B;margin:0 0 4px">'+esc(w.name)+'</h3>'+(w.role?'<p style="font-family:Lato,Arial,sans-serif;font-size:14px;line-height:1.4;color:#566772;margin:0 0 14px">'+esc(w.role)+'</p>':'')+'<div style="text-align:left">'+(w.showEmail?'<p style="font-family:Lato,Arial,sans-serif;font-size:15px;line-height:1.45;margin:0 0 9px"><strong>Email:</strong><br><a href="mailto:'+safeUrl(w.email)+'" style="color:'+w.accent+';font-weight:700;word-break:break-word">'+esc(w.email)+'</a></p>':'')+(w.showOffice?'<p style="font-family:Lato,Arial,sans-serif;font-size:15px;line-height:1.45;margin:0 0 9px"><strong>Office:</strong><br>'+esc(w.office)+'</p>':'')+(w.showOfficeHours?'<p style="font-family:Lato,Arial,sans-serif;font-size:15px;line-height:1.45;margin:0 0 12px"><strong>Office hours:</strong><br>'+esc(w.officeHours)+'</p>':'')+'</div>'+(w.showTeams?'<a href="https://teams.microsoft.com/l/chat/0/0?users='+encodeURIComponent(w.email)+'" target="_blank" rel="noopener" style="display:block;text-align:center;background:'+w.accent+';color:'+on+';text-decoration:none;padding:10px 14px;border-radius:6px;font-family:Lato,Arial,sans-serif;font-size:15px;line-height:1.3;font-weight:700;margin-top:14px">💬 Message me on Teams</a>':'')+'</div>';
    if(w.template==='links'){
      var links=[['Syllabus',w.syllabusUrl||'#'],['Student Email','https://outlook.office.com/mail/?realm=mclennan.edu'],['Online Tutoring','https://www.mclennan.edu/academic-support-and-tutoring/tutor.html'],['Tech Support','https://www.mclennan.edu/tech-support/'],['Student Support','https://www.mclennan.edu/campus-resource-guide/on-campus-resources.html']];
      body='<div style="background:#FFFFFF;border:1px solid #D5E0E5;border-top:0;border-radius:0 0 8px 8px;padding:16px">'+links.map(function(x){return '<a href="'+safeUrl(x[1])+'" target="_blank" rel="noopener" style="display:block;background:'+w.accent+';color:'+on+';text-decoration:none;text-align:center;border-radius:6px;padding:10px 12px;margin:0 0 9px;font-family:Lato,Arial,sans-serif;font-size:15px;font-weight:700">'+esc(x[0])+'</a>'}).join('')+'</div>';
    }
    if(w.template==='weekly')body='<div style="background:#FFFFFF;border:1px solid #D5E0E5;border-top:0;border-radius:0 0 8px 8px;padding:18px"><p style="font-family:Lato,Arial,sans-serif;font-size:13px;color:'+w.accent+';font-weight:700;text-transform:uppercase;letter-spacing:.06em;margin:0 0 10px">'+esc(w.date)+'</p><p style="font-family:Lato,Arial,sans-serif;font-size:15px;line-height:1.55;color:#1F2933;margin:0 0 14px">'+nl(w.content)+'</p><ul style="font-family:Lato,Arial,sans-serif;font-size:15px;color:#1F2933;margin:0 0 15px;padding-left:22px">'+lines(w.items).map(function(x){return '<li style="margin:0 0 8px">'+esc(x)+'</li>'}).join('')+'</ul>'+widgetButton(w,on)+'</div>';
    if(w.template==='announcement')body='<div style="background:#FFFFFF;border:1px solid #D5E0E5;border-top:0;border-radius:0 0 8px 8px;padding:18px"><p style="font-family:Lato,Arial,sans-serif;font-size:13px;color:'+w.accent+';font-weight:700;margin:0 0 10px">'+esc(w.date)+'</p><p style="font-family:Lato,Arial,sans-serif;font-size:15px;line-height:1.6;color:#1F2933;margin:0 0 '+(w.buttonLabel?'15px':'0')+'">'+nl(w.content)+'</p>'+widgetButton(w,on)+'</div>';
    if(w.template==='blank')body='<div style="background:#FFFFFF;border:1px solid #D5E0E5;border-top:0;border-radius:0 0 8px 8px;padding:18px"><p style="font-family:Lato,Arial,sans-serif;font-size:15px;line-height:1.6;color:#1F2933;margin:0 0 '+(w.buttonLabel?'15px':'0')+'">'+nl(w.content)+'</p>'+widgetButton(w,on)+'</div>';
    return '<div style="width:100%;max-width:320px;box-sizing:border-box;font-family:Lato,Arial,sans-serif">'+widgetHeader(w)+body+'</div>';
  }
  function widgetButton(w,on){return w.buttonLabel?'<a href="'+safeUrl(w.buttonUrl||'#')+'" style="display:block;text-align:center;background:'+w.accent+';color:'+on+';text-decoration:none;padding:10px 14px;border-radius:6px;font-family:Lato,Arial,sans-serif;font-size:15px;font-weight:700">'+esc(w.buttonLabel)+'</a>':''}
  function widgetField(label,key,value,type){type=type||'text';return '<label>'+esc(label)+(type==='textarea'?'<textarea data-widget-key="'+key+'" rows="5">'+esc(value)+'</textarea>':'<input type="'+type+'" data-widget-key="'+key+'" value="'+esc(value)+'">')+'</label>'}
  function checkField(label,key,value){return '<label class="cm-check-label"><input type="checkbox" data-widget-check="'+key+'" '+(value?'checked':'')+'><span>'+esc(label)+'</span></label>'}
  function widgetControls(){
    var w=state.widget,out='<section><h2>Widget template</h2><label>Starting template<select id="cm-widget-template">'+Object.keys(widgetInfo).map(function(k){return '<option value="'+k+'" '+(w.template===k?'selected':'')+'>'+esc(widgetInfo[k][0])+'</option>'}).join('')+'</select></label><p class="cm-field-note">'+esc(widgetInfo[w.template][1])+'</p></section><section><h2>Widget editor</h2>'+widgetField('Widget title','title',w.title)+widgetField('Short subtitle','subtitle',w.subtitle)+'<fieldset><legend>Widget color</legend>'+swatches(w.accent,'widget-color')+'<p class="cm-field-note">'+contrastNote(w.accent)+'</p></fieldset>';
    if(w.template==='instructor')out+=widgetField('Instructor name','name',w.name)+widgetField('Title or role','role',w.role)+widgetField('Email address','email',w.email,'email')+'<p class="cm-field-note">The email creates both the email and Teams links.</p>'+checkField('Show instructor image','showImage',w.showImage)+(w.showImage?widgetField('Image URL','imageUrl',w.imageUrl):'')+checkField('Show email link','showEmail',w.showEmail)+checkField('Show office location','showOffice',w.showOffice)+(w.showOffice?widgetField('Office location','office',w.office):'')+checkField('Show office hours','showOfficeHours',w.showOfficeHours)+(w.showOfficeHours?widgetField('Office hours','officeHours',w.officeHours):'')+checkField('Show “Message me on Teams” button','showTeams',w.showTeams);
    if(w.template==='links')out+=widgetField('Syllabus URL','syllabusUrl',w.syllabusUrl)+'<p class="cm-field-note">Student Email, Online Tutoring, Tech Support, and Student Support use MCC’s standard links automatically.</p>';
    if(w.template==='weekly')out+=widgetField('Week or date label','date',w.date)+widgetField('Weekly summary','content',w.content,'textarea')+widgetField('Tasks (one per line)','items',w.items,'textarea')+widgetField('Optional button label','buttonLabel',w.buttonLabel)+widgetField('Optional button URL','buttonUrl',w.buttonUrl);
    if(w.template==='announcement')out+=widgetField('Date or status','date',w.date)+widgetField('Announcement','content',w.content,'textarea')+widgetField('Optional button label','buttonLabel',w.buttonLabel)+widgetField('Optional button URL','buttonUrl',w.buttonUrl);
    if(w.template==='blank')out+=widgetField('Widget content','content',w.content,'textarea')+widgetField('Optional button label','buttonLabel',w.buttonLabel)+widgetField('Optional button URL','buttonUrl',w.buttonUrl);
    return out+'</section>';
  }
  function renderWidgetBuilder(){
    state.view='widgets';updateNav();var code=widgetHTML();
    main.innerHTML='<div class="cm-builder-page">'+breadcrumbs(['Build','Widget Builder'])+'<div class="cm-shell cm-builder-heading"><div><p class="cm-eyebrow cm-eyebrow-dark">Brightspace homepage widgets</p><h1>Build a course widget</h1><p>Create a compact, responsive widget and copy its self-contained HTML into Brightspace.</p></div><div class="cm-top-actions"><button class="cm-button cm-secondary" id="cm-download-widget">Download HTML</button><button class="cm-button cm-primary" id="cm-copy-widget">Copy widget HTML</button></div></div><div class="cm-shell cm-widget-shell"><aside class="cm-panel">'+widgetControls()+'</aside><section class="cm-workspace"><div class="cm-workspace-label"><h2>Widget preview</h2><span>Maximum width: 320px</span></div><div class="cm-widget-preview-stage"><div id="cm-widget-render">'+code+'</div></div><div class="cm-builder-note"><strong>Widget-safe output:</strong> Inline styles only, no page header markup, no style sheets, and no scripts.</div></section><aside class="cm-panel cm-widget-code-panel"><div class="cm-panel-inner"><h2>Widget code snippet</h2><p class="cm-field-note">This code updates as you customize the widget.</p><code class="cm-code" id="cm-widget-code">'+esc(code)+'</code><div class="cm-code-actions"><button type="button" id="cm-copy-widget-code">Copy widget HTML</button></div></div></aside></div><section class="cm-section cm-shell"><p class="cm-eyebrow cm-eyebrow-dark">Brightspace walkthrough</p><h2>Add the widget to a course homepage</h2><p>Use either guide to open the Brightspace homepage editor and paste the finished widget HTML.</p><div class="cm-help-links"><a class="cm-button cm-primary" href="https://youtu.be/ItXixUVR300?si=0_dC1Wr00gIqMuvj" target="_blank" rel="noopener">Watch the video</a><a class="cm-button cm-secondary" href="https://scribehow.com/embed/Brightspace_how_to_edit_a_course_homepage_and_edit_Instructor_Widget__QgXLWjDySP-rgZySQU1oNQ" target="_blank" rel="noopener">Open the Scribe walkthrough</a></div><div class="cm-scribe"><iframe src="https://scribehow.com/embed/Brightspace_how_to_edit_a_course_homepage_and_edit_Instructor_Widget__QgXLWjDySP-rgZySQU1oNQ" width="800" height="679" allow="fullscreen" title="Brightspace homepage and instructor widget walkthrough"></iframe></div></section></div>';
    bindWidgetBuilder();
  }
  function refreshWidgetPreview(){var code=widgetHTML(),preview=document.getElementById('cm-widget-render'),snippet=document.getElementById('cm-widget-code');if(preview)preview.innerHTML=code;if(snippet)snippet.textContent=code}
  function bindWidgetBuilder(){
    document.getElementById('cm-widget-template').addEventListener('change',function(){state.widget=makeWidget(this.value);renderWidgetBuilder()});
    document.querySelectorAll('[data-widget-key]').forEach(function(el){var key=el.getAttribute('data-widget-key');el.addEventListener('input',function(){state.widget[key]=el.value;refreshWidgetPreview()})});
    document.querySelectorAll('[data-widget-check]').forEach(function(el){el.addEventListener('change',function(){state.widget[el.getAttribute('data-widget-check')]=el.checked;renderWidgetBuilder()})});
    document.querySelectorAll('[data-widget-color]').forEach(function(btn){btn.addEventListener('click',function(){state.widget.accent=btn.getAttribute('data-widget-color');renderWidgetBuilder()})});
    ['cm-copy-widget','cm-copy-widget-code'].forEach(function(id){document.getElementById(id).addEventListener('click',function(){copyText(widgetHTML(),'Widget HTML copied.')})});
    document.getElementById('cm-download-widget').addEventListener('click',function(){downloadText('<!DOCTYPE html><html lang="en"><body>'+widgetHTML()+'</body></html>','MCC-Brightspace-Widget.html')});
  }

  function renderTemplates(){
    state.view='templates';updateNav();
    main.innerHTML=breadcrumbs(['Build','Page Templates'])+'<section class="cm-hero"><div class="cm-shell cm-hero-inner"><div><p class="cm-eyebrow">Start with structure</p><h1>Page templates</h1><p class="cm-hero-copy">Pick a proven page pattern, customize the content in the builder, and copy clean HTML into Brightspace.</p></div><div class="cm-hero-motif" aria-hidden="true"><span>M</span></div></div></section><section class="cm-section cm-shell"><div class="cm-template-grid">'+Object.keys(templates).map(function(k){var t=templates[k],tone=t.tone||'';return '<article class="cm-template-card"><div class="cm-template-thumb"><div class="cm-thumb-banner" style="background:'+(tone==='red'?'#B42318':tone==='yellow'?'#9A6700':tone==='green'?'#18794E':'#003366')+'"></div><div class="cm-thumb-title"></div><div class="cm-thumb-line"></div><div class="cm-thumb-line cm-short"></div><div class="cm-thumb-box"></div></div><div class="cm-template-card-body"><span class="cm-template-kicker">'+(tone?'AI stoplight policy':'Brightspace page')+'</span><h2>'+esc(t.name)+'</h2><p>'+esc(t.description)+'</p><button type="button" class="cm-button cm-primary" data-use-template="'+k+'">Use this template</button></div></article>'}).join('')+'</div></section>';
    document.querySelectorAll('[data-use-template]').forEach(function(btn){btn.addEventListener('click',function(){state.page=makePage(btn.getAttribute('data-use-template'));state.selected=null;renderPageBuilder();main.focus()})});
  }
  function renderSupport(){
    state.view='support';updateNav();
    main.innerHTML=breadcrumbs(['Support'])+'<section class="cm-hero"><div class="cm-shell cm-hero-inner"><div><p class="cm-eyebrow">We can help</p><h1>CourseMaker support</h1><p class="cm-hero-copy">Get help with the builder, Brightspace HTML, accessibility, or course design.</p></div><div class="cm-hero-motif" aria-hidden="true"><span>M</span></div></div></section><section class="cm-section cm-shell"><div class="cm-support-grid"><article class="cm-support-card cm-featured"><span class="cm-template-kicker">Instructional design</span><h2>Plan or improve a course page</h2><p>Get help with organization, accessibility, student directions, and the learning experience.</p><a href="mailto:online@mclennan.edu">Email online@mclennan.edu</a></article><article class="cm-support-card"><span class="cm-template-kicker">Brightspace support</span><h2>Troubleshoot the page</h2><p>We can help when content does not paste, display, or behave the way you expected.</p><a href="mailto:online@mclennan.edu">Request technical help</a></article><article class="cm-support-card"><span class="cm-template-kicker">Suggest an addition</span><h2>Request a template or block</h2><p>Tell us what you keep rebuilding in Brightspace. Strong ideas can become shared CourseMaker components.</p><a href="mailto:online@mclennan.edu?subject=CourseMaker%20Suggestion">Send a suggestion</a></article></div></section><section class="cm-section cm-section-soft"><div class="cm-shell"><p class="cm-eyebrow cm-eyebrow-dark">Quick guides</p><h2>Build, check, and publish</h2><div class="cm-card-grid"><article class="cm-card"><span class="cm-card-number">STEP 1</span><h2>Set up the page</h2><p>Choose a template, write the page label and Heading 1, select a title style, and optionally add an image URL.</p></article><article class="cm-card"><span class="cm-card-number">STEP 2</span><h2>Add and edit blocks</h2><p>Add blocks from the left. Select a block in the preview to edit it, then use the controls to reorder it.</p></article><article class="cm-card"><span class="cm-card-number">STEP 3</span><h2>Check accessibility</h2><p>Use logical headings, meaningful links, useful image descriptions, accurate captions, and content that does not rely on color alone.</p></article><article class="cm-card"><span class="cm-card-number">STEP 4</span><h2>Move it to Brightspace</h2><p>Copy the page HTML into the Brightspace HTML source editor, or upload the downloaded HTML file, then preview as a learner.</p></article></div></div></section><section class="cm-section cm-shell"><p class="cm-eyebrow cm-eyebrow-dark">Widget help</p><h2>Add widgets to a Brightspace homepage</h2><div class="cm-support-grid"><article class="cm-support-card cm-featured"><span class="cm-template-kicker">Video guide</span><h2>Watch the widget walkthrough</h2><p>See how to open the homepage editor and add or update a custom widget.</p><a href="https://youtu.be/ItXixUVR300?si=0_dC1Wr00gIqMuvj" target="_blank" rel="noopener">Watch the Brightspace video</a></article><article class="cm-support-card"><span class="cm-template-kicker">Step-by-step guide</span><h2>Follow the Scribe walkthrough</h2><p>Use the visual instructions for editing a course homepage and its Instructor Widget.</p><a href="https://scribehow.com/embed/Brightspace_how_to_edit_a_course_homepage_and_edit_Instructor_Widget__QgXLWjDySP-rgZySQU1oNQ" target="_blank" rel="noopener">Open the Scribe walkthrough</a></article></div></section><section class="cm-section cm-section-soft"><div class="cm-narrow"><p class="cm-eyebrow cm-eyebrow-dark">Frequently asked questions</p><h2>Answers before the panic button</h2><div class="cm-faq"><details><summary>Do I need to know HTML?</summary><p>No. The Page Builder handles the HTML while you edit through form fields and a visual preview.</p></details><details><summary>Can I edit the page after copying it?</summary><p>Yes. The output is standard HTML with inline styles, so it can be revised in Brightspace or rebuilt in CourseMaker.</p></details><details><summary>Will this work with the New Content Experience?</summary><p>The generated pages use responsive, self-contained HTML intended for Brightspace content pages. Always preview the finished page in your course.</p></details><details><summary>Can I use other colors?</summary><p>The builder uses approved MCC colors plus black and white for brand consistency and accessible contrast.</p></details><details><summary>Why might CourseMaker not run after pasting?</summary><p>CourseMaker itself requires JavaScript. Upload this complete HTML file to Brightspace Manage Files instead of pasting only its visible content. Your generated widget snippets contain no scripts.</p></details></div></div></section>';
  }
  function renderHome(){
    state.view='home';updateNav();
    main.innerHTML='<section class="cm-hero"><div class="cm-shell cm-hero-inner"><div><p class="cm-eyebrow">MCC Brightspace course design</p><h1>Build your Brightspace page</h1><p class="cm-hero-copy">Create complete course pages or compact homepage widgets. Every builder produces editable HTML you control.</p><div class="cm-hero-actions"><button class="cm-button cm-primary" data-view="builder">Open Page Builder</button></div></div><div class="cm-hero-motif" aria-hidden="true"><span>M</span></div></div></section><section class="cm-section cm-shell"><div class="cm-comparison"><article class="cm-card"><span class="cm-card-number">01</span><h2>Page templates</h2><p>Ready-made layouts for the pages faculty create most often.</p><button data-view="templates">View templates →</button></article><article class="cm-card cm-featured"><span class="cm-card-number">02</span><h2>Page builder</h2><p>A visual workspace for assembling, editing, and reordering blocks.</p><button data-view="builder">Launch builder →</button></article><article class="cm-card"><span class="cm-card-number">03</span><h2>Widget builder</h2><p>Compact, responsive snippets for Brightspace course homepages.</p><button data-view="widgets">Build a widget →</button></article></div><div class="cm-decision"><table><caption>Which option should I use?</caption><thead><tr><th>If you want to…</th><th>Start here</th><th>Experience level</th></tr></thead><tbody><tr><td>Create a common course page quickly</td><td><button class="cm-text-button" data-view="templates">Page templates</button></td><td>Beginner to advanced</td></tr><tr><td>Design a custom page visually</td><td><button class="cm-text-button" data-view="builder">Page builder</button></td><td>Beginner to advanced</td></tr><tr><td>Create a course homepage widget</td><td><button class="cm-text-button" data-view="widgets">Widget builder</button></td><td>Beginner to advanced</td></tr></tbody></table></div></section>';
    bindViewButtons();
  }
  function renderSearch(query){
    state.view='search';updateNav();var q=query.toLowerCase(),items=[['Page Builder','Build complete Brightspace pages with templates and blocks.','builder'],['Page templates','Course content, instructor, module overview, AI stoplight, and blank pages.','templates'],['Widget Builder','Instructor information, important links, weekly, announcement, and blank widgets.','widgets'],['Support','Brightspace guidance, accessibility, videos, and Scribe walkthrough.','support']].filter(function(x){return (x[0]+' '+x[1]).toLowerCase().indexOf(q)>-1});
    main.innerHTML=breadcrumbs(['Search'])+'<section class="cm-hero"><div class="cm-shell"><p class="cm-eyebrow">CourseMaker search</p><h1>Results for “'+esc(query)+'”</h1><p class="cm-hero-copy">Find templates, tools, guides, and support.</p></div></section><section class="cm-section cm-narrow"><p><strong>'+items.length+'</strong> '+(items.length===1?'result':'results')+'</p><div class="cm-results">'+(items.length?items.map(function(x){return '<article><h2><button class="cm-text-button" data-view="'+x[2]+'">'+esc(x[0])+'</button></h2><p>'+esc(x[1])+'</p></article>'}).join(''):'<h2>No matching pages</h2><p>Try a broader phrase, or email <a href="mailto:online@mclennan.edu">online@mclennan.edu</a> for help.</p>')+'</div></section>';bindViewButtons();
  }
  function updateNav(){document.querySelectorAll('#cm-navigation [data-view]').forEach(function(btn){var current=state.view===btn.dataset.view;if(current)btn.setAttribute('aria-current','page');else btn.removeAttribute('aria-current')})}
  function go(view){if(view==='builder')renderPageBuilder();else if(view==='templates')renderTemplates();else if(view==='widgets')renderWidgetBuilder();else if(view==='support')renderSupport();else renderHome();main.focus();window.scrollTo({top:root.offsetTop,behavior:'smooth'});bindViewButtons()}
  function bindViewButtons(){document.querySelectorAll('#mcc-coursemaker [data-view]').forEach(function(btn){if(btn.dataset.bound)return;btn.dataset.bound='1';btn.addEventListener('click',function(){go(btn.getAttribute('data-view'))})})}
  document.getElementById('cm-menu').addEventListener('click',function(){var nav=document.getElementById('cm-navigation'),open=nav.classList.toggle('cm-open');this.setAttribute('aria-expanded',String(open))});
  document.getElementById('cm-search-form').addEventListener('submit',function(e){e.preventDefault();var q=document.getElementById('cm-search-input').value.trim();if(q)renderSearch(q)});
  bindViewButtons();renderHome();
})();
